import {NumberChecker} from "@/Composables/Checkers/NumberChecker"

export function ScientificChecker(options) {

	return {
		format: () => {
			if (isNaN(options[0])) {
				return "rÃĐponse en notation scientifique"
			} else {
				return `rÃĐponse en notation scientifique Ã  ${options[0]} chiffre(s) significatif(s)`
			}
		},
		check: (expectedAnswer, answer = []) => {
			// Le rÃĐsultat est exactement ce qui est demandÃĐ
			if (answer.toString() === expectedAnswer.toString()) {
				return {
					result: true,
					message: ""
				}
			}

			// On vÃĐrifie que le format est bien de type scientifique.
			const PS = +(answer.split("*")[0]),
				OG = +(answer.split("10^")[1] || 0),
				ePS = +(expectedAnswer.split("*")[0]),
				eOG = +(expectedAnswer.split("10^")[1] || 0)

			if (!answer.includes("*10^")) {
				return {
					result: false,
					message: "le format de rÃĐponse n'est pas une notation scientifique."
				}
			}

			// On vÃĐrifie la partie significative
			if (PS < 1 || PS >= 10) {
				return {
					result: false,
					message: "la partie significative n'est pas entre 1 et 10 (non compris)"
				}
			}

			if (PS !== ePS) {
				return {
					result: false,
					message: "erreur dans la partie significative: " + new NumberChecker(options).check(ePS, PS).message
				}
			}


			// On vÃĐrifie l'ordre de grandeur.
			if (OG !== eOG) {
				return {
					result: false,
					message: "l'ordre de grandeur n'est pas juste.."
				}
			}


			// Il n'y a pas d'option -> le rÃĐsultat ne peut pas ÃŠtre validÃĐ.
			if (options.length === 0) {
				return {
					result: false,
					message: " ? "
				}
			}

			// Nombre de dÃĐcimales souhaitÃĐes
			const nbDecimales = +options[0]
			// Nomber de dÃĐcimale de la rÃĐponse
			let crtDecimales = answer.toString().split(".")

			// Le nombre de chiffres aprÃĻs la virgule n'est pas juste
			if (crtDecimales.length === 1 || crtDecimales[1].length !== nbDecimales) {
				return {
					result: false,
					message: `Il faut ${nbDecimales} chiffre(s) aprÃĻs la virgule.`
				}
			}

			// Le dernier chiffre n'est pas juste - il s'agit peut ÃŠtre d'un problÃĻme d'arrondi ?
			if (crtDecimales[crtDecimales.length - 1] - expectedAnswer.toString()[expectedAnswer.toString().length - 1] === 1) {
				return {
					result: false,
					message: "Peut ÃŠtre un problÃĻme d'arrondi ?"
				}
			}
		}

	}

}
